output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?service ?name WHERE {
  VALUES ?promotion {
    wd:Q186791 wd:Q63367366 wd:Q765888
  }
  ?promotion wdt:P355 ?service .
  ?service wdt:P31 / wdt:P279 * wd:Q2065988 .
  ?service rdfs:label ?name .
  FILTER(LANG(?name) = "en")
}

